And the function declaration that tells Neon what to deploy:

// neon.ts
import { defineConfig } from '@neon/config/v1';
export default defineConfig({
preview: {
functions: {
contacts: { name: 'contacts mcp server', source: 'src/index.ts' },
},
},
});

